from typing import TypedDict, Optional

class CleanState(TypedDict):
    query: str
    assigned_role: Optional[str]   # None when no assignment is active
    result: Optional[str]

def reset_role_node(state: CleanState) -> dict:
    """Clears assignment before entering next assignment cycle."""
    return {"assigned_role": None, "result": None}

def classifier_node(state: CleanState) -> dict:
    # Only classify if no role is currently assigned
    if state.get("assigned_role"):
        return {}   # no-op: role still active
    # ... classify and return {"assigned_role": "retriever"}
    return {"assigned_role": "retriever"}

# Typical cycle:
#  classifier → specialist → reset_role → classifier (loop)
# Each reset_role call wipes the stale assignment before the
# next classification, preventing cross-turn role bleed.
